import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Package, Truck, ArrowLeft, ShoppingBag, Calendar, Info } from 'lucide-react';
import { toast } from 'react-toastify';
import api from '../api/api';
import OrderTracker from '../components/orders/OrderTracker';
import '../assets/styles/Orders.css';

const Orders = () => {
  const navigate = useNavigate();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchOrders = useCallback(async () => {
    try {
      const data = await api.get('/api/order');
      if (data.success) {
        setOrders(data.orders);
      }
    } catch (err) {
      console.error('Failed to fetch orders', err);
      toast.error('Could not load your orders');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/');
      toast.error('Please login to view your orders');
      return;
    }
    fetchOrders();
    window.scrollTo(0, 0);
  }, [fetchOrders, navigate]);

  // --- Simulation Helper ---
  const simulateStatus = (orderId) => {
    const statusOrder = ['Order Placed', 'In Transit', 'Out for Delivery', 'Delivered'];
    setOrders(prev => prev.map(o => {
      if (o.id === orderId) {
        const nextIdx = (statusOrder.indexOf(o.status) + 1) % statusOrder.length;
        return { ...o, status: statusOrder[nextIdx] };
      }
      return o;
    }));
  };

  return (
    <div className="orders-page-container">
      <div className="orders-content-wrapper">
        <header className="orders-header">
          <button className="back-btn-fancy" onClick={() => navigate('/')}>
            <ArrowLeft size={18} />
            <span>Back to Shop</span>
          </button>
          <div className="header-text">
            <h1>My Order History</h1>
            <p>Track your artisanal heritage deliveries</p>
          </div>
        </header>

        {loading ? (
          <div className="orders-loading">
            <div className="spinner"></div>
            <p>Retrieving your orders...</p>
          </div>
        ) : orders.length > 0 ? (
          <div className="orders-list-grid">
            {orders.map((order) => (
              <div key={order.id} className="order-card-large">
                <div className="card-top">
                  <div className="order-meta">
                    <div className="meta-item">
                      <Package size={14} className="icon" />
                      <span className="label">Order ID:</span>
                      <span className="value">{order.orderId}</span>
                    </div>
                    <div className="meta-item">
                      <Calendar size={14} className="icon" />
                      <span className="label">Placed on:</span>
                      <span className="value">{new Date(order.createdAt).toLocaleDateString()}</span>
                    </div>
                  </div>
                  <div className="order-total-badge">
                    <span className="label">Amount Paid</span>
                    <span className="value">₹{order.amount.toFixed(2)}</span>
                  </div>
                </div>

                <div className="card-tracker-section">
                  <div className="section-header">
                    <h3>Delivery Progress</h3>
                    <button 
                      className="demo-simulate-btn"
                      onClick={() => simulateStatus(order.id)}
                    >
                      <Truck size={14} /> Simulate Next Stage
                    </button>
                  </div>
                  <OrderTracker status={order.status} />
                </div>

                <div className="order-items-preview">
                  <h4>Items in this Order</h4>
                  <div className="items-row">
                    {order.items.map((item, idx) => (
                      <div key={idx} className="mini-item-card">
                        <img src={item.image} alt={item.title} />
                        <div className="item-info">
                          <span className="name">{item.title}</span>
                          <span className="qty">{item.quantity} x {item.weight}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="order-footer">
                  <div className="shipping-info">
                    <Info size={14} />
                    <span>Deliver to: {order.address.city}, {order.address.state}</span>
                  </div>
                  <button className="reorder-btn">View Details</button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="orders-empty">
            <ShoppingBag size={64} strokeWidth={1} />
            <h2>No orders found</h2>
            <p>Your history is empty, but your cart doesn't have to be!</p>
            <button className="start-shopping-btn" onClick={() => navigate('/products')}>
              Browse Collection
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Orders;
